import React, { useState, useEffect } from 'react';
import io from 'socket.io-client';
import axios from 'axios';
import Login from './components/Login';
import Register from './components/Register';
import ChatList from './components/ChatList';
import ChatWindow from './components/ChatWindow';
import Profile from './components/Profile';

const socket = io(process.env.REACT_APP_SOCKET_URL || 'http://localhost:5000');

function App() {
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [conversations, setConversations] = useState([]);
  const [selectedConversation, setSelectedConversation] = useState(null);
  const [messages, setMessages] = useState([]);
  const [showProfile, setShowProfile] = useState(false);

  useEffect(() => {
    if (token) {
      const userData = JSON.parse(localStorage.getItem('user'));
      setUser(userData);
      socket.emit('user-online', userData.id);
      fetchConversations();
    }
  }, [token]);

  useEffect(() => {
    if (selectedConversation) {
      fetchMessages(selectedConversation._id);
    }
  }, [selectedConversation]);

  useEffect(() => {
    // Слушаем новые сообщения
    socket.on('new-message', (message) => {
      if (selectedConversation && 
          message.conversation === selectedConversation._id) {
        setMessages(prev => [...prev, message]);
      }
      
      // Обновляем список чатов
      setConversations(prev => 
        prev.map(conv => 
          conv._id === message.conversation 
            ? { ...conv, lastMessage: message }
            : conv
        )
      );
    });

    socket.on('message-sent', (message) => {
      if (selectedConversation && 
          message.conversation === selectedConversation._id) {
        setMessages(prev => [...prev, message]);
      }
    });

    socket.on('user-status', ({ userId, online }) => {
      // Обновляем статус в списке чатов
      setConversations(prev => 
        prev.map(conv => ({
          ...conv,
          participants: conv.participants.map(p => 
            p._id === userId ? { ...p, online } : p
          )
        }))
      );
    });

    socket.on('typing-indicator', ({ userId, conversationId, isTyping }) => {
      if (selectedConversation && selectedConversation._id === conversationId) {
        // Показываем индикатор
        const otherUser = selectedConversation.participants.find(p => p._id === userId);
        // Тут можно обновить состояние для отображения "печатает"
      }
    });

    socket.on('messages-read', ({ conversationId, userId }) => {
      if (selectedConversation && selectedConversation._id === conversationId) {
        setMessages(prev => 
          prev.map(msg => 
            msg.sender._id !== userId ? { ...msg, read: true } : msg
          )
        );
      }
    });

    return () => {
      socket.off('new-message');
      socket.off('message-sent');
      socket.off('user-status');
      socket.off('typing-indicator');
      socket.off('messages-read');
    };
  }, [selectedConversation]);

  const fetchConversations = async () => {
    try {
      const res = await axios.get('/api/conversations', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setConversations(res.data);
    } catch (error) {
      console.error('Ошибка загрузки чатов:', error);
    }
  };

  const fetchMessages = async (conversationId) => {
    try {
      const res = await axios.get(`/api/messages/${conversationId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setMessages(res.data);
      
      // Отмечаем сообщения как прочитанные
      socket.emit('message-read', {
        conversationId,
        userId: user.id
      });
    } catch (error) {
      console.error('Ошибка загрузки сообщений:', error);
    }
  };

  const sendMessage = (text) => {
    if (!selectedConversation || !text.trim()) return;
    
    socket.emit('send-message', {
      conversationId: selectedConversation._id,
      senderId: user.id,
      text
    });
  };

  const handleTyping = (isTyping) => {
    if (selectedConversation) {
      socket.emit('typing', {
        conversationId: selectedConversation._id,
        userId: user.id,
        isTyping
      });
    }
  };

  const handleLogin = (userData, userToken) => {
    setUser(userData);
    setToken(userToken);
    localStorage.setItem('token', userToken);
    localStorage.setItem('user', JSON.stringify(userData));
    socket.emit('user-online', userData.id);
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setUser(null);
    setToken(null);
    setConversations([]);
    setSelectedConversation(null);
    socket.disconnect();
  };

  if (!token) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-50">
        <div className="container mx-auto px-4 py-8">
          <h1 className="text-4xl font-bold text-center mb-8 text-gray-800">
            Chatty
          </h1>
          <div className="max-w-md mx-auto">
            <Login onLogin={handleLogin} />
            <Register onRegister={handleLogin} />
          </div>
        </div>
      </div>
    );
  }

  if (showProfile) {
    return (
      <Profile 
        user={user}
        token={token}
        onClose={() => setShowProfile(false)}
        onUpdate={(updatedUser) => setUser(updatedUser)}
      />
    );
  }

  return (
    <div className="flex h-screen bg-gray-100">
      <ChatList 
        conversations={conversations}
        currentUser={user}
        selectedConversation={selectedConversation}
        onSelectConversation={setSelectedConversation}
        onLogout={handleLogout}
        onProfileClick={() => setShowProfile(true)}
      />
      <ChatWindow 
        conversation={selectedConversation}
        messages={messages}
        currentUser={user}
        onSendMessage={sendMessage}
        onTyping={handleTyping}
      />
    </div>
  );
}

export default App;
